patch:
--- a/adder.v
+++ b/adder.v
@@ -1,13 +1,13 @@
 module simple_adder(
   input [7:0] a,
   input [7:0] b,
-  output [15:0] sum
+  output [15:0] result
 );
   assign result = a + b;
 endmodule

 module top;
   reg [7:0] x, y;
   wire [15:0] z;
-  simple_adder adder_inst (.a(x), .b(y), .sum(z));
+  simple_adder adder_inst (.a(x), .b(y), .result(z));
 endmodule

before_code:
module simple_adder(
  input [7:0] a,
  input [7:0] b,
  output [15:0] result
);
  assign result = a + b;
endmodule

module top;
  reg [7:0] x, y;
  wire [15:0] z;
  simple_adder adder_inst (.a(x), .b(y), .sum(z));
endmodule

after_code:
module simple_adder(
  input [7:0] a,
  input [7:0] b,
  output [15:0] result
);
  assign result = a + b;
endmodule

module top;
  reg [7:0] x, y;
  wire [15:0] z;
  simple_adder adder_inst (.a(x), .b(y), .result(z));
endmodule
